// ═══════════════════════════════════════════════════════
// Procesar cambio de config recibido desde el panel
// ═══════════════════════════════════════════════════════
const body = $json.body || $json;
const { action, key, value, timestamp } = body;

console.log(`[CONFIG UPDATE] action=${action} key=${key} ts=${timestamp}`);

// Guardamos en memoria de ejecución para que el flujo principal la use
// en la próxima ejecución (n8n no tiene estado global entre ejecuciones,
// pero Supabase ya fue actualizado por el panel)
return [{ json: { ok: true, action, key, message: `Config '${key}' procesada` } }];

// ═══════════════════════════════════════════════════════
// ENTRADA: Prepara sesión + mensaje del usuario
// ═══════════════════════════════════════════════════════
const sessionId = $json.sessionId || $execution?.id || 'default';
const userMsg = (
  $json.chatInput ||
  $json.message ||
  $json.text ||
  ''
).trim();

return [{ json: { ...$json, sessionId, userMsg } }];

// ═══════════════════════════════════════════════════════
// Construir mapa key→value de la configuración del bot
// ═══════════════════════════════════════════════════════
const configRows = $input.all().map(i => i.json);
const config = {};
for (const row of configRows) {
  config[row.key] = row.value;
}

// Pasar la config al contexto de la ejecución
return [{ json: { botConfig: config } }];

// ═══════════════════════════════════════════════════════
// Combinar config + endpoints en un solo objeto
// ═══════════════════════════════════════════════════════
const botConfig = $('Construir Mapa Config').first().json.botConfig || {};
const endpoints = $input.all().map(i => i.json);

// Endpoint principal para leads (primer endpoint activo con key 'lead_erp' o el primero)
const leadEndpoint = endpoints.find(e => e.key === 'lead_erp') || endpoints[0] || null;

return [{ json: { botConfig, endpoints, leadEndpoint } }];

// ═══════════════════════════════════════════════════════
// Guardar respuesta del agente
// ═══════════════════════════════════════════════════════
const sessionId = $('Preparar Sesion').first().json.sessionId;
const agentRaw = ($json.output || '').trim();
const agentLimpio = agentRaw.replace(/LEAD_CAPTURED[\s\S]*/gi, '').trim();

return [{ json: { ...$json, sessionId, agentLimpio } }];

// ═══════════════════════════════════════════════════════
// Detectar si hay LEAD_CAPTURED en el output
// ═══════════════════════════════════════════════════════
const rawOutput = ($('Preparar Respuesta Agente').first().json.output || '').trim();

if (!rawOutput) {
  return [{ json: { output: 'Solicitud recibida. ¿En qué más puedo ayudarte?', hasLead: false } }];
}

const corteIndex = rawOutput.search(/LEAD_CAPTURED\s*[:({]/);
let cleanOutput = rawOutput;
let leadPart = null;

if (corteIndex !== -1) {
  cleanOutput = rawOutput.substring(0, corteIndex).trim();
  leadPart = rawOutput.substring(corteIndex).trim();
}

cleanOutput = cleanOutput
  .replace(/LEAD_CAPTURED[\s\S]*/gi, '')
  .replace(/\{[\s\S]*"nombre"[\s\S]*\}/gi, '')
  .trim();

if (/^[\[{]/.test(cleanOutput)) cleanOutput = '';

if (leadPart) {
  try {
    const jsonMatch = leadPart.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const leadData = JSON.parse(jsonMatch[0]);
      const nombre   = (leadData.nombre   || '').replace(/[\[\]]/g, '').trim();
      const email    = (leadData.email    || '').replace(/[\[\]]/g, '').trim();
      const telefono = (leadData.telefono || '').replace(/[\[\]]/g, '').trim();

      const tieneplaceholders = ['[nombre]','[email]','[telefono]','[nombre real]','[email real]','[telefono real]']
        .some(p => nombre.toLowerCase() === p || email.toLowerCase() === p || telefono.toLowerCase() === p);

      const esValido = !tieneplaceholders
        && nombre.length > 1
        && (/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email) || telefono.replace(/\D/g, '').length >= 6);

      if (esValido) {
        if (!cleanOutput) {
          cleanOutput = `Perfecto, ${nombre}. Ya lo tenemos apuntado, te contactamos en breve. Cualquier duda, aquí estoy.`;
        }
        return [{
          json: {
            output: cleanOutput,
            hasLead: true,
            lead: {
              nombre,
              email,
              telefono,
              producto_interes: (leadData.producto_interes || 'General').replace(/[\[\]]/g, '').trim(),
              contexto:         (leadData.contexto || '').trim(),
              origen:           (leadData.origen || 'chatbot').trim(),
              timestamp:        leadData.timestamp || new Date().toISOString()
            }
          }
        }];
      }
    }
  } catch (e) {}
}

return [{ json: { output: cleanOutput || 'Disculpa, ¿en qué más puedo ayudarte?', hasLead: false } }];

// ═══════════════════════════════════════════════════════
// Preparar body de la API usando el endpoint configurado
// desde Supabase (no hardcodeado)
// ═══════════════════════════════════════════════════════
const lead = $json.lead;
const ts   = lead.timestamp || new Date().toISOString();
const cfg  = $('Merge Config + Endpoints').first().json;
const campaniaId = cfg.botConfig?.lead_campania_id || '50';

const bodyApi = {
  asunto: `Demo chatbot: ${lead.producto_interes} | ${lead.email} | ${ts}`,
  detalle: lead.contexto || '',
  origen: 'chatbot',
  erp_campania_comercial_id: campaniaId,
  cliente: {
    nombre:   lead.nombre,
    email:    lead.email,
    empresa:  '',
    telefono: lead.telefono
  }
};

const endpoint = cfg.leadEndpoint || {
  url:            'https://dev.estratosplus.com/estratos/api/v1/erp/AutomatizacionOportunidadesWs/set_oportunidad',
  method:         'POST',
  api_key_header: 'x-estratos-api-key',
  api_key_value:  'c1544aa59ebd3372531edbeb88c55bda'
};

return [{ json: { lead, bodyApiString: JSON.stringify(bodyApi), endpoint } }];

const lead = $('Preparar Body API').item.json.lead;
const respuesta = $json;

return [{
  json: {
    nombre:           lead.nombre,
    email:            lead.email,
    telefono:         lead.telefono,
    producto_interes: lead.producto_interes || 'General',
    contexto:         lead.contexto || '',
    origen:           lead.origen || 'chatbot',
    estado:           'OK',
    error_detalle:    null,
    respuesta_api:    JSON.stringify(respuesta)
  }
}];

const lead = $('Preparar Body API').item.json.lead;
const error = $json;

let errorDetalle = '';
try {
  const errObj = typeof error === 'string' ? JSON.parse(error) : error;
  errorDetalle = errObj.message || errObj.error || JSON.stringify(errObj);
} catch(e) {
  errorDetalle = JSON.stringify(error);
}

return [{
  json: {
    nombre:           lead.nombre,
    email:            lead.email,
    telefono:         lead.telefono,
    producto_interes: lead.producto_interes || 'General',
    contexto:         lead.contexto || '',
    origen:           lead.origen || 'chatbot',
    estado:           'ERROR',
    error_detalle:    errorDetalle,
    respuesta_api:    null
  }
}];

// ═══════════════════════════════════════════════════════
// TRANSCRIPT: preparar datos
// ═══════════════════════════════════════════════════════
const sessionId = $('Preparar Sesion').first().json.sessionId;
const logData   = $('Preparar Log OK1').item?.json || {};
const transcriptFormat = $('Merge Config + Endpoints').first().json.botConfig?.transcript_format || 'html';

return [{
  json: {
    sessionId,
    transcriptFormat,
    leadNombre: logData.nombre           || 'Desconocido',
    leadEmail:  logData.email            || '',
    leadTel:    logData.telefono         || '',
    leadProd:   logData.producto_interes || 'General',
    leadCtx:    logData.contexto         || ''
  }
}];

// ═══════════════════════════════════════════════════════════════
// GENERAR TRANSCRIPT según formato configurado en el panel
// Soporta: html | json | pdf (pdf genera HTML que Supabase guarda
// con extensión .pdf — para PDF real añadir nodo de conversión)
// ═══════════════════════════════════════════════════════════════
const prepData = $('Preparar Datos Transcript').first().json;
const format   = (prepData.transcriptFormat || 'html').toLowerCase();
const { leadNombre, leadEmail, leadTel, leadProd, leadCtx } = prepData;

const items   = $input.all();
const historia = items.map(i => i.json).filter(m => m.role && m.content);

const now           = new Date();
const timestamp     = now.toISOString();
const fechaLegible  = now.toLocaleString('es-ES', { timeZone: 'Europe/Madrid' });
const fileTimestamp = timestamp.replace(/[:.]/g, '-').replace('T', '_').slice(0, 19);

function esc(str) {
  return String(str || '')
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;').replace(/\n/g, '<br>');
}

let fileContent, fileName, storagePath, contentType;

if (format === 'json') {
  // ── JSON ─────────────────────────────────────────────────
  const output = {
    meta: { generated_at: timestamp, lead_nombre: leadNombre, lead_email: leadEmail, message_count: historia.length },
    lead: { nombre: leadNombre, email: leadEmail, telefono: leadTel, producto: leadProd, contexto: leadCtx },
    messages: historia.map(m => ({ role: m.role, content: m.content, created_at: m.created_at || null }))
  };
  fileContent  = JSON.stringify(output, null, 2);
  fileName     = `transcript_${fileTimestamp}.json`;
  storagePath  = `chatbot/transcript_${fileTimestamp}.json`;
  contentType  = 'application/json';

} else {
  // ── HTML (también para pdf hasta tener nodo de conversión) ─
  const mensajesHtml = historia.length
    ? historia.map(msg => {
        const isUser  = msg.role === 'user';
        const label   = isUser ? '👤 Usuario' : '🤖 Asistente';
        const bgColor = isUser ? '#EEF2FF' : '#F0FDF4';
        const border  = isUser ? '#818CF8' : '#4ADE80';
        const labelClr = isUser ? '#3730A3' : '#166534';
        const hora    = msg.created_at
          ? new Date(msg.created_at).toLocaleTimeString('es-ES', { timeZone: 'Europe/Madrid', hour: '2-digit', minute: '2-digit' })
          : '';
        return `<div style="margin-bottom:14px;padding:14px 18px;background:${bgColor};border-left:4px solid ${border};border-radius:0 8px 8px 0;">
  <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px;">
    <span style="font-size:11px;font-weight:700;color:${labelClr};text-transform:uppercase;">${label}</span>
    ${hora ? `<span style="font-size:11px;color:#9CA3AF;">${hora}</span>` : ''}
  </div>
  <div style="font-size:14px;line-height:1.7;color:#1F2937;">${esc(msg.content)}</div>
</div>`;
      }).join('')
    : '<p style="color:#6B7280;font-style:italic;">No hay mensajes.</p>';

  const fichaLead = `<div style="margin-top:28px;padding:18px 20px;background:#FFF7ED;border:1px solid #FED7AA;border-radius:8px;">
  <div style="font-size:11px;font-weight:700;color:#92400E;text-transform:uppercase;margin-bottom:14px;">📋 Datos del lead</div>
  <table style="width:100%;border-collapse:collapse;font-size:13px;">
    <tr><td style="padding:5px 12px 5px 0;color:#6B7280;width:130px;">Nombre</td><td style="padding:5px 0;color:#111827;font-weight:500;">${esc(leadNombre)}</td></tr>
    <tr><td style="padding:5px 12px 5px 0;color:#6B7280;">Email</td><td>${esc(leadEmail)}</td></tr>
    <tr><td style="padding:5px 12px 5px 0;color:#6B7280;">Teléfono</td><td>${esc(leadTel)}</td></tr>
    <tr><td style="padding:5px 12px 5px 0;color:#6B7280;">Producto</td><td>${esc(leadProd)}</td></tr>
    ${leadCtx ? `<tr><td style="padding:5px 12px 5px 0;color:#6B7280;">Contexto</td><td>${esc(leadCtx)}</td></tr>` : ''}
  </table>
</div>`;

  fileContent = `<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><title>Transcript – Aicor</title></head><body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#F9FAFB;padding:32px 16px">
<div style="max-width:780px;margin:0 auto;background:#fff;border-radius:12px;box-shadow:0 1px 4px rgba(0,0,0,.12);overflow:hidden">
  <div style="background:linear-gradient(135deg,#1E40AF,#2563EB);color:#fff;padding:28px 32px">
    <h1 style="font-size:20px;font-weight:600;margin:0 0 8px">📋 Transcript</h1>
    <p style="font-size:13px;opacity:.85;margin:0">🕐 ${fechaLegible}<br>👤 ${esc(leadNombre)}${leadEmail ? ' &lt;' + esc(leadEmail) + '&gt;' : ''}<br>📨 ${historia.length} mensajes</p>
  </div>
  <div style="padding:28px 32px">${mensajesHtml}${fichaLead}</div>
  <div style="background:#F3F4F6;padding:14px 32px;font-size:11px;color:#9CA3AF;">Generado por Aicor Chatbot · ${timestamp}</div>
</div></body></html>`;

  const ext       = format === 'pdf' ? 'pdf' : 'html';
  fileName        = `transcript_${fileTimestamp}.${ext}`;
  storagePath     = `chatbot/transcript_${fileTimestamp}.${ext}`;
  contentType     = format === 'pdf' ? 'application/pdf' : 'text/html; charset=utf-8';
}

return [{
  json: {
    html_content:   fileContent,
    file_name:      fileName,
    lead_nombre:    leadNombre,
    lead_email:     leadEmail,
    created_at:     timestamp,
    message_count:  historia.length,
    storage_path:   storagePath,
    content_type:   contentType
  }
}];

const uploadResponse = $json;
const prevData = $('Generate Transcript (multi-format)').item.json;
const storagePath = prevData.storage_path;
const publicUrl   = `https://uovfdghgbanhjojtobtz.supabase.co/storage/v1/object/public/transcripts/${storagePath}`;
const uploadOk    = uploadResponse.statusCode >= 200 && uploadResponse.statusCode < 300;

return [{
  json: {
    file_url:        uploadOk ? publicUrl : null,
    storage_path:    storagePath,
    file_name:       prevData.file_name,
    lead_nombre:     prevData.lead_nombre,
    lead_email:      prevData.lead_email,
    message_count:   prevData.message_count,
    created_at:      prevData.created_at,
    upload_status:   uploadOk ? 'OK' : 'ERROR',
    upload_response: JSON.stringify(uploadResponse)
  }
}];

